UPDATE public.questions SET
  stimulus_text = 'In her essay on urban soundscapes, writer 3 argues that city planners should treat noise pollution as a public-health issue, citing studies linking traffic noise to elevated stress hormones. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours a day, leaving residents with fragmented sleep even when air quality meets regulatory standards. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work and heightened irritability at home. The writer contrasts cosmetic beautification projects—new planters and paint—with measurable acoustic interventions such as berms, low-noise pavement, and delivery-time restrictions. She acknowledges that complete silence is impossible in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest improvements in green space. The essay concludes that sound belongs in urban planning budgets alongside light and air. Pilot programs in three cities reported measurable sleep gains after targeted speed reductions on arterial roads.',
  question_text = 'Which choice most logically follows from the passage as a whole?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"Readers should dismiss the study because laboratory conditions never resemble real classrooms or ecosystems.","is_correct":false,"explanation":"The passage acknowledges limits but still draws implications; it does not urge total dismissal."},{"id":"B","text":"The described mechanism could inform practice or policy beyond the immediate case, though the authors stop short of universal claims.","is_correct":true,"explanation":"Implication items reward reasonable extension with acknowledged bounds."},{"id":"C","text":"The passage proves that every similar system will behave identically in all future circumstances.","is_correct":false,"explanation":"The passage explicitly cautions against overgeneralization."},{"id":"D","text":"The authors conceal contradictory data that would invalidate the reported pattern.","is_correct":false,"explanation":"No evidence of concealed data appears in the text."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The passage supports a bounded implication rather than absolute proof. The stimulus anchors the correct choice in language such as "In her essay on urban soundscapes, writer 3 argues that city planners should treat noise pollution a…". Choice B is correct: . Incorrect options contradict explicit details, import absent information, or answer a different question than the stem asks.',
